import py4godot.classes.StreamPeerSocket as py4godot_streampeersocket 
from py4godot.wrappers.wrappers import CPPStreamPeerUDSWrapper


class StreamPeerUDS(py4godot_streampeersocket.StreamPeerSocket):
  r'''
		A stream peer that handles UNIX Domain Socket (UDS) connections. This object can be used to connect to UDS servers, or also is returned by a UDS server. Unix Domain Sockets provide inter-process communication on the same machine using the filesystem namespace.
		**Note:** UNIX Domain Sockets are only available on UNIX-like systems (Linux, macOS, etc.) and are not supported on Windows.
	'''

  @staticmethod
  def constructor():
    class_ = StreamPeerUDS.construct_without_init()
    class_._ptr = constructor(846,0, ())
    return class_
  @staticmethod
  def new():
    class_ = StreamPeerUDS.construct_without_init()
    class_._ptr = constructor(846,0, ())
    return class_
  def __init__(self):
    self._ptr =  CPPStreamPeerUDSWrapper()
    self.casted_from = None
    if c_utils.shouldCreateObject:
      self._ptr = constructor(846,0, ())


  def generate_wrapper(self):
    return CPPStreamPeerUDSWrapper()
  def init_signals(self):
    super().init_signals()

  @staticmethod
  def construct_without_init():
    cls = StreamPeerUDS.__new__(StreamPeerUDS)
    cls.shouldBeDeleted = True
    cls.casted_from = None
    cls.constructed_from_python = False
    cls.init_signals()
    return cls
  @staticmethod
  def get_type():
    return 'StreamPeerUDS'

  def __del__(self):
    if self.casted_from is None:
      self._ptr.call_with_return(94, ())
      self._ptr = None
  @staticmethod
  def cast(other:'Object'):
    assert other != None # Object to be casted must not be None
    cls = StreamPeerUDS.construct_without_init()
    cls._ptr = CPPStreamPeerUDSWrapper()
    cls._ptr_before = other._ptr # Save pointer
    cls._ptr.copy_gdowner(cls._ptr_before)
    cls.casted_from = other
    return cls
  @staticmethod
  def cast_without_reference(other: 'Object'):
    assert other != None # Object to be casted must not be None
    cls = StreamPeerUDS.construct_without_init()
    cls._ptr = CPPStreamPeerUDSWrapper()
    cls._ptr_before = other._ptr # Save pointer
    cls._ptr.copy_gdowner(cls._ptr_before)
    return cls

  @functools.native_method
  def bind(self, path:'str'   ) -> typing.Union[int]:
    r'''
				Opens the UDS socket, and binds it to the specified socket path.
				This method is generally not needed, and only used to force the subsequent call to `connect_to_host` to use the specified `path` as the source address.
			'''

    assert(not path is None)
    assert isinstance(path, (str, String)), 'path must be str or String'





    assert(isinstance(path, (str, String)))
    py_string_path = path if isinstance(path, StringName) else c_utils.py_string_to_string(path)

    _ret:int
    _ret = self._ptr.call_with_return(91,tuple([py_string_path._ptr]))
    return _ret


  @functools.native_method
  def connect_to_host(self, path:'str'   ) -> typing.Union[int]:
    r'''
				Connects to the specified UNIX Domain Socket path. Returns `constant OK` on success.
			'''

    assert(not path is None)
    assert isinstance(path, (str, String)), 'path must be str or String'





    assert(isinstance(path, (str, String)))
    py_string_path = path if isinstance(path, StringName) else c_utils.py_string_to_string(path)

    _ret:int
    _ret = self._ptr.call_with_return(92,tuple([py_string_path._ptr]))
    return _ret


  @functools.native_method
  def get_connected_path(self) -> typing.Union[str]:
    r'''
				Returns the socket path of this peer.
			'''




    _ret = String.construct_without_init()
    _ret._ptr = self._ptr.call_with_return(93,tuple([]))
    return utils.gd_string_to_py_string(_ret)



register_cast_function('StreamPeerUDS', StreamPeerUDS.cast)
register_class('StreamPeerUDS', StreamPeerUDS)
